UPDATE group_cart_item SET
	item_quantity		= #{itemQuantity},
	base_amount			= #{baseAmount},
	option_extra_amount	= #{optionExtraAmount},
	item_total_amount	= #{itemTotalAmount}
WHERE cart_item_idx		= #{cartItemIdx}

UPDATE group_cart_item SET
	item_status		= 'REMOVED'
WHERE cart_item_idx = #{cartItemIdx}
